class Solution {
    public int minimizeXor(int num1, int num2) {
        int count = Integer.bitCount(num2);
        for (int i = 1; i <= 1000000000; i++) {
            if (Integer.bitCount(i) == count && (i ^ num1) < Integer.MIN_VALUE) {
                return i;
            }
        }
        return 0;
    }
}
